Here's a thorough review of `app.js` with security-focused improvements for error handling and input validation:

---

## Current Issues

The app is minimal but has several gaps from a security and robustness standpoint:

1. **No body parsing or input validation** — No middleware to handle/sanitize incoming request bodies.
2. **No error handling middleware** — Unhandled errors will crash the server or leak stack traces.
3. **No rate limiting** — Endpoints are wide open to abuse.
4. **Hardcoded data / no pagination** — The `/users` endpoint returns everything with no limits.
5. **Missing security headers** — No `helmet` or equivalent to set secure HTTP headers.
6. **No request logging** — Makes incident detection/debugging very hard.
7. **Port hardcoded** — Should come from environment config.
8. **No graceful shutdown** — Abrupt termination can leave connections hanging.

---

## Suggested Improvements

Here's a revised version with inline comments explaining each change:

```js
'use strict';

const express = require('express');
const helmet = require('helmet');           // Secure HTTP headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();
const PORT = process.env.PORT || 3000;

// ── Security Headers ──────────────────────────────────────────────────────────
// Sets X-Frame-Options, X-Content-Type-Options, HSTS, CSP, etc.
app.use(helmet());

// ── Body Parsing ──────────────────────────────────────────────────────────────
// Limit body size to prevent large-payload DoS attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// ── Rate Limiting ─────────────────────────────────────────────────────────────
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // Max 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// ── Routes ────────────────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Input validation: sanitize and bound any query params
    const page = Math.max(1, parseInt(req.query.page, 10) || 1);
    const limit = Math.min(100, Math.max(1, parseInt(req.query.limit, 10) || 10));

    const allUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const start = (page - 1) * limit;
    const paginated = allUsers.slice(start, start + limit);

    res.json({ data: paginated, page, limit, total: allUsers.length });
  } catch (err) {
    next(err); // Forward to centralized error handler
  }
});

// ── 404 Handler ───────────────────────────────────────────────────────────────
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ── Centralized Error Handler ─────────────────────────────────────────────────
// Must have exactly 4 parameters for Express to treat it as an error handler
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Never leak stack traces to the client in production
  const isDev = process.env.NODE_ENV === 'development';
  console.error(err); // Log the full error server-side

  res.status(err.status || 500).json({
    error: err.message || 'Internal server error',
    ...(isDev && { stack: err.stack }), // Only expose stack in dev
  });
});

// ── Server Start ──────────────────────────────────────────────────────────────
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// ── Graceful Shutdown ─────────────────────────────────────────────────────────
const shutdown = (signal) => {
  console.log(`${signal} received. Shutting down gracefully...`);
  server.close(() => {
    console.log('HTTP server closed.');
