  console.error(err.stack); // Log internally
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message
  });
});
```

#### 5. No 404 Handler
Unmatched routes fall through to Express's default response, which leaks framework information.

```js
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});
```

#### 6. Hardcoded Port
Port `3000` should come from an environment variable to avoid conflicts and allow secure deployment configuration.

```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

---

### 🟡 Best Practice Improvements

#### 7. No CORS Policy
Without explicit CORS configuration, cross-origin behavior is unpredictable. Be explicit:

```js
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  methods: ['GET', 'POST'],
}));
```

