4. **No global error handler** — Unhandled errors will leak stack traces to clients in development, and crash in production without a safety net.

5. **Hardcoded data with no validation** — The `/users` endpoint returns static data now, but has no guard against future query parameters being used unsafely (e.g., SQL injection if a DB is added).

6. **No 404 handler** — Unknown routes return Express's default HTML error, which leaks framework info.

7. **`console.log` in production** — Prefer a structured logger (e.g., `pino`, `winston`) to avoid leaking internal details in production logs.

---

### Suggested Improved Version

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security Middleware ---

// Set secure HTTP headers
app.use(helmet());

// Parse JSON bodies with a size limit to prevent payload bombs
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Rate limiting: max 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate & sanitize any query params before use
    const { page = 1, limit = 20 } = req.query;
    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);

    if (isNaN(pageNum) || pageNum < 1 || isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
      return res.status(400).json({ error: 'Invalid pagination parameters.' });
    }

    // Static data shown here — apply same validation when wiring to a DB
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (err) {
    next(err); // Forward to global error handler
  }
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Resource not found.' });
});

// --- Global Error Handler ---
// Catches any error passed via next(err)
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  const isDev = process.env.NODE_ENV === 'development';

  // Never leak stack traces in production
  console.error(err); // Replace with structured logger in production
  res.status(err.status || 500).json({
    error: isDev ? err.message : 'An internal server error occurred.',
    ...(isDev && { stack: err.stack }),
  });
});

// --- Server ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

### Summary of Changes

| Area | Change | Reason |
|---|---|---|
| **Headers** | Add `helmet()` | Prevents common web vulnerabilities via HTTP headers |
| **Rate limiting** | Add `express-rate-limit` | Mitigates DoS and brute-force attacks |
| **Body parsing** | Add `express.json({ limit: '10kb' })` | Prevents payload bomb attacks; enables safe body parsing |
| **Input validation** | Validate & sanitize query params | Prevents injection and unexpected behavior |
| **Error handling** | Add global `(err, req, res, next)` handler | Prevents stack trace leaks in production |
| **404 handling** | Add catch-all 404 middleware | Avoids leaking framework info via default HTML errors |
| **Config** | Use `process.env.PORT` | Avoids hardcoded config; follows 12-factor app principles |

### New Dependencies to Install
```bash
npm install helmet express-rate-limit
```

